// 1. Busy list from Google Calendar
const busyList = $input.first().json.calendars['2005fadiakl@gmail.com'].busy;

// 2. Get the ISO time from Vapi (e.g., "2026-02-16T17:00:00Z")
const rawArgs = $('Webhook').item.json.body.message.toolCalls[0].function.arguments;
const argsObject = typeof rawArgs === 'string' ? JSON.parse(rawArgs) : rawArgs;
const requestedStartStr = argsObject.BookingTime;

if (!requestedStartStr) throw new Error("BookingTime is missing!");

// 3. Create Date objects directly (No splitting needed!)
const requestedStart = new Date(requestedStartStr);
const requestedEnd = new Date(requestedStart.getTime() + 60 * 60 * 1000); // +1 hour

// 4. Overlap check
const hasConflict = busyList.some(b => {
  const bStart = new Date(b.start);
  const bEnd = new Date(b.end);
  return requestedStart < bEnd && requestedEnd > bStart;
});

return {
  json: {
    available: !hasConflict,
    debug_requested_start: requestedStart.toISOString(),
    debug_requested_end: requestedEnd.toISOString(),
    debug_busy_slots: busyList.length
  }
};

// Busy list from Google Calendar
const busyList = $input.first().json.calendars['2005fadiakl@gmail.com'].busy;

// Raw booking time (user input)
const raw = $('Webhook').item.json.body.message.toolCalls[0].function.arguments.BookingTime;
// "2025-10-13 12:00"

// Build requested slot explicitly in France time (+02:00 here)
const iso = raw.replace(' ', 'T') + ':00'; // 2025-10-13T12:00:00
const requestedStart = new Date(iso + '+02:00');

// End = end of same day
const requestedEnd = new Date(requestedStart);
requestedEnd.setHours(23, 59, 59, 0);

// Overlap check
const hasConflict = busyList.some(b => {
  const bStart = new Date(b.start);
  const bEnd = new Date(b.end);

  return requestedStart < bEnd && requestedEnd > bStart;
});

return {
  available: !hasConflict,
  debug_requested_start: requestedStart.toISOString(),
  debug_requested_end: requestedEnd.toISOString()
};

